INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (1, '竹竿', '削片竹+棉线，最朴素的钓竿，新手村大爷送你的那种。如果你说"这都不能算钓竿"，那是因为你还没真正钓过鱼。', 1, 'shop', 100, 1, 1, 0, 99, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (2, '玻璃钢钓竿', '工业玻璃纤维杆，便宜耐用，村口便利店和加油站都有售。看着没什么气质，但比竹竿不知道高到哪里去.', 2, 'shop', 5000, 1.01, 1, 0, 199, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (3, '碳素纤维竿', '现代工艺的结晶，不过还不是巅峰，这种只是性价比好所以卖得最多。', 3, 'shop', 25000, 1.02, 1, 0.01, 399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (4, '钛合金多节竿', '钛合金骨架，轻巧又坚韧，可拆卸成数节便于携带。出门远钓的中端选择，把它从拉杆箱里掏出来的那一刻起，旁人就会觉得你是认真的钓鱼佬。', 4, 'shop', 100000, 1.03, 1.01, 0.02, 699, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (5, '高模量碳布矶竿', '海钓店挂在墙上当镇店之宝的款式，碳布层数堆到极致以求轻量化和韧性。话说镇店之宝怎么这么轻易就让搬走？', 5, 'shop', 1000000, 1.05, 1.01, 0.03, 1111, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (6, '电动收线智能竿', '内置力矩感应器和小型马达，号称"能自动应对所有鱼"。注意，它只是把"什么时候收线"代劳了，"什么时候不收"还是你的问题。', 6, 'shop', 2500000, 1.07, 1.02, 0.04, 2144, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (7, '触须钓线', '一根没有竿身、只有不停蠕动的触须的"钓竿"。你不太确定到底是你在钓它还是它在钓你，但效果出奇地好，别纠结了。', 7, 'gacha', NULL, 1.1, 1.05, 0.06, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (8, '黏液浮标杆', '杆身覆盖着不知名的黏液，鱼咬钩时还会渗出更多。第一次握的时候你想吐，第二次握的时候你麻木了，第三次握的时候你开始好奇这是不是某种生物的体液。', 7, 'gacha', NULL, 1.09, 1.08, 0.04, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (9, '神经传导钓竿', '竿身嵌入未知生物的活体神经，传导着水下的搏动让你"听见"鱼的存在。顺手让你做了几个噩梦。', 7, 'gacha', NULL, 1.13, 1.02, 0.05, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (10, '桃木伏波竿', '道士伏水驱邪用的桃木杆，鱼来不犯主人；只是这"主人"的定义有点模糊，鱼好像觉得是它们自己。', 7, 'gacha', NULL, 1.12, 1.04, 0.04, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (11, '紫竹仙人钓', '传说是某位谪仙人下凡时随手插在地上的紫竹，几百年后被钓鱼佬挖出来当竿用。能勾来灵性鱼，但灵性鱼会跟你讲道理，你也得做好辩论的准备。', 7, 'gacha', NULL, 1.13, 1.05, 0.05, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (12, '钓灵符', '持符即竿，化道为线。修士眼里这是工具，钓鱼佬眼里这是玄学；但反正钓得到鱼，那就够了。', 7, 'gacha', NULL, 1.11, 1.02, 0.06, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (13, '溪语者', '镶嵌月光苔的银桦木竿，竿尖流淌水流纹路的符文；月光的祝福让每次垂钓能有额外收获，一定程度上对稀有生物有吸引力。', 7, 'gacha', NULL, 1.1, 1.08, 0.05, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (14, '雷云捕手', '使用风暴巨鹰尾羽打造的紫纹钓竿，缠绕静电火花，你感觉麻麻的，鱼也感觉麻麻的。这算不算在电鱼啊？', 7, 'gacha', NULL, 1.09, 1.06, 0.04, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (15, '古龙鳞竿', '老龙脱落的鳞片缝在杆头，用龙的气息镇压水中之物。你的鱼竿因此散发出一股老龙才有的——怎么说呢，老人味。但鱼好像很受用。', 7, 'gacha', NULL, 1.12, 1.04, 0.05, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (16, '虫洞投射钓竿', '握柄内置虫洞发生器，能让鱼饵直接出现在深水区，能大幅提升接触稀有鱼类的机会，以及触底的风险。', 7, 'gacha', NULL, 1.09, 1.02, 0.07, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (17, '纳米修复钓竿', '表面覆盖自修复纳米涂层，被鱼撕裂的钓线能缓慢再生。因此，你和鱼谁先撑不住就完全要看你的水平了。', 7, 'gacha', NULL, 1.12, 1.05, 0.04, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (18, '量子纠缠钓竿', '钓线由量子纤维编织，当鱼咬钩时，竿体会分裂出虚幻的平行时空投影干扰鱼类（和你的）判断。', 7, 'gacha', NULL, 1.1, 1.08, 0.05, 4399, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (19, '共生触腕', '表面布满搏动血管的触手缠绕上你的手臂……看起来它可以无限延长，能更加轻松地够到那些居住在深海中的东西，但你时常感觉自己仿佛要被它反向拖入深渊……', 8, 'gacha', NULL, 1.15, 1.05, 0.07, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (20, '尖细的羊蹄竿', '一根漆黑的又尖又细的羊蹄，断面伸出密麻的触手…你差不多看习惯了。这些触手让你一次性有更大鱼获，但它来者不拒，经常抓到杂鱼。', 8, 'gacha', NULL, 1.12, 1.12, 0.05, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (21, '黏稠漆黑的羊蹄竿', '这竿羊蹄通体漆黑又黏又滑，竿体还包裹着未蜕尽的胎衣，它似乎在孕育新的钓竿？以你的视界还无法理解。', 8, 'gacha', NULL, 1.13, 1.1, 0.04, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (22, '诛仙竿', '曾有一柄赫赫有名的仙剑，名为诛仙剑，因诛杀太多修士而染上了邪气，因此被其主人亲手毁掉……它的碎片被重铸成此鱼竿，为的是让它在垂钓过程中修身养性，洗蜕杀气。这便是为什么你拿着它就想抽旁边的钓友的原因了。', 8, 'gacha', NULL, 1.16, 1.04, 0.06, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (23, '百炼成仙竿', '匠人对自己的作品始终不满意，反复重铸后让此鱼竿诞生了器灵，不过由于是新生的灵，除了自称是鱼竿仙、非常喋喋不休以外什么都帮不了你，也就鱼竿本身的质量确实过硬。', 8, 'gacha', NULL, 1.17, 1.05, 0.05, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (24, '万竿归宗', '一钩化千万，一杆抵万杆，虽然不能一把拉起千万条，但钓起来的可能性变高了，就是用起来有点累。', 8, 'gacha', NULL, 1.15, 1.06, 0.06, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (25, '冰晶溯流竿', '寒冰核心锻造的透蓝钓竿，接触水面会凝结霜花…由于寒冷鱼类变得行动迟缓，在被举报污染环境之前，尽全力回本吧。', 8, 'gacha', NULL, 1.16, 1.05, 0.05, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (26, '龙王骨竿', '传说中某条魔龙的脊椎打磨而成，触感冰冷如同它生前盘踞的王座。挥动时鱼群仿佛感受到龙王的威压，纷纷主动来朝拜。', 8, 'gacha', NULL, 1.14, 1.09, 0.06, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (27, '古精灵之杆', '由精灵长老亲手雕琢，竿身刻满古老咒文。垂钓时它会发出极轻微的歌声，鱼听了便迷醉而上钩。同一首歌你听久了倒不会迷醉，只会困得想睡觉。', 8, 'gacha', NULL, 1.16, 1.08, 0.05, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (28, '奇点引擎钓竿', '以模拟黑洞奇点为核心动力，产生引力漩涡吸引范围鱼群。在它吸入沉船残骸之前还是挺好用的。', 8, 'gacha', NULL, 1.14, 1.09, 0.07, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (29, '时空回流竿', '竿头嵌入时空回溯装置，鱼咬钩的瞬间它会把鱼"拉回"几秒前的位置——就在它差点逃跑的那一刻。物理学家会反对，但鱼不会。', 8, 'gacha', NULL, 1.16, 1.04, 0.06, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (30, '反物质钓针', '针尖由反物质构成，接触即湮灭，普通的鱼一靠近就完蛋。但偶尔会有鱼因稀有特性而幸存，那就是你今天的好运。', 8, 'gacha', NULL, 1.12, 1.04, 0.08, 6666, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (31, '神经罗网', '投入神经做成的罗网，沉下啸叫状的人面浮标。它的目标似乎十分明确……那就是永不空军。', 9, 'gacha', NULL, 1.19, 1.05, 0.08, 9999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (32, '古神舌竿', '某些神伸出舌头变成的钓竿。你不知道这是它的祝福还是它的玩笑，反正你拿着它钓鱼比谁都顺。神已经亲自下场作弊了，鱼还能怎么办？', 9, 'gacha', NULL, 1.17, 1.11, 0.08, 9999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (33, '捆仙竿', '由捆仙绳改造的鱼竿，甩竿即可自动捆鱼。但本性难移，若是捆到路过修士要记得道歉。', 9, 'gacha', NULL, 1.18, 1.09, 0.06, 9999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (34, '混沌青莲竿', '世间常道善恶只在一念间，善恶纠缠是为混沌；于混沌中诞生出淤泥而不染，是为青莲。', 9, 'gacha', NULL, 1.2, 1.06, 0.07, 9999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (35, '巨龙锁链鞭', '由曾妄想锁住龙神的链条的碎片改造而成，现在都还残留着龙神的怒气。鱼见了钩瑟瑟发抖，你也有点瑟瑟发抖，龙神指不定哪天会算错账到你头上。', 9, 'gacha', NULL, 1.17, 1.12, 0.07, 9999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (36, '破邪竿', '鱼钩闪烁圣光，竿身燃烧着永不熄灭的圣火。第一个用它的人想用来烤鱼，结果发现这火不烫鱼也不烫人，如果你觉得烫，说明你有问题。', 9, 'gacha', NULL, 1.19, 1.05, 0.07, 9999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (37, '引力收束竿', '竿头能产生局部重力场，扭曲鱼群的游动轨迹直接撞向你的鱼钩。物理学家会指出这不符合任何已知定律，所以它显然不是任何已知定律下的产物。', 9, 'gacha', NULL, 1.16, 1.14, 0.06, 9999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (38, '量子折叠钓针', '钓针同时存在于多个时空，让它的渔获存在着万千可能性；观测的那一刻才决定结局。请稳定地观测。', 9, 'gacha', NULL, 1.18, 1.12, 0.08, 9999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (39, '我到底钓到了什么？！', '拉起钓竿的那刻，你忽然意识到你同时钓起了所有鱼、同时没能钓鱼任何鱼、同时钓起了一条杂鱼、同时钓起了一条诡异的鱼、同时……什么叫游戏发生错误将终止客户端？', 10, 'shop', NULL, 1.21, 1.12, 0.09, 99999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (40, '太上忘情竿', '采用三十三重天冰蚕丝铸成，上钩之鱼皆一副生死看淡、看破凡尘之相。所以也有些失恋的人潜水是为了找这个钩。', 10, 'shop', NULL, 1.23, 1.06, 0.08, 99999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (41, '巴哈姆特的金鳞爪', '白金龙王巴哈姆特蜕下的一片金属爪鳞，由神圣界的工匠重铸为钓竿。线为金质，钩为银齿，挥动时金鳞流泻圣光。但请记住巴哈姆特是善良龙之神，所以你钓鱼也得讲基本法。', 10, 'shop', NULL, 1.22, 1.1, 0.08, 99999, NULL);
INSERT INTO "rods" ("rod_id", "name", "description", "rarity", "source", "purchase_cost", "bonus_fish_quality_modifier", "bonus_fish_quantity_modifier", "bonus_rare_fish_chance", "durability", "icon_url") VALUES (42, '戴森光束竿', '连接轨道卫星的星能传输系统，钓线为聚焦太阳光束。理论上能钓起恒星物质，但偶尔会因能量过载熔毁鱼钩…以及一些倒霉的鱼…还有一些倒霉的你。', 10, 'shop', NULL, 1.2, 1.18, 0.09, 99999, NULL);
